    { question: "Read: 'I like the book Fun at School. The book is funny.' What kind of book is it?", options: ["Scary","Funny","Sad","Old"], correctIndex: 1, difficulty: "easy", explanation: "The text says 'The book is funny', so it is a funny book." },
    { question: "Read: 'My favorite book is about a girl. She goes to a magic forest. She meets a talking rabbit.' Where does the girl go?", options: ["To a magic forest","To a school","To a city","To a mountain"], correctIndex: 0, difficulty: "medium", explanation: "The text says 'She goes to a magic forest', so the answer is a magic forest." },
    { question: "Read: 'I love the book The Little Star. It is exciting. I read it every night.' What does 'exciting' mean?", options: ["Boring","Very interesting","Small","New"], correctIndex: 1, difficulty: "medium", explanation: "'Exciting' means very interesting or fun, so the book is not boring." },
    { question: "Read: 'My favorite book is The Three Friends. Tom and Ana find a map. They go to an island. They see a big treasure.' What happens last in the story?", options: ["They find a map","They go to an island","They see a big treasure","They meet a dog"], correctIndex: 2, difficulty: "hard", explanation: "The story order is: find map, go to island, see treasure. So seeing treasure is last." }
